var bulkPartTypesList = [];
var bulkLocationsList = [];
function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt)) return d;
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function toTitleCase(str) {
  if (!str) return str;
  return str.toLowerCase().replace(/\b\w/g, function (c) {
    return c.toUpperCase();
  });
}
function makeSearchable(inputId, dropdownId, hiddenId, getList, labelKey, valueKey) {
  function render(filter) {
    var dd = document.getElementById(dropdownId);
    if (!dd) return;
    var list = getList();
    var filtered = filter ? list.filter(function (item) {
      return String(item[labelKey]).toLowerCase().indexOf(filter.toLowerCase()) > -1;
    }) : list;
    if (!filtered.length) {
      dd.innerHTML = '<div class="search-option no-results">No results</div>';
    } else {
      dd.innerHTML = filtered.map(function (item) {
        return '<div class="search-option" data-id="' + item[valueKey] + '" data-label="' + String(item[labelKey]).replace(/"/g, '&quot;') + '">' + item[labelKey] + '</div>';
      }).join('');
      dd.querySelectorAll('.search-option[data-id]').forEach(function (el) {
        el.addEventListener('click', function () {
          document.getElementById(inputId).value = this.getAttribute('data-label');
          document.getElementById(hiddenId).value = this.getAttribute('data-id');
          dd.classList.remove('open');
        });
      });
    }
    dd.classList.add('open');
  }
  var inp = document.getElementById(inputId);
  if (inp && !inp.dataset.bound) {
    inp.dataset.bound = 'true';
    inp.addEventListener('focus', function () {
      render(this.value);
    });
    inp.addEventListener('input', function () {
      render(this.value);
    });
  }
}
document.addEventListener('click', function (e) {
  ['bulk_part_type_wrap', 'bulk_location_wrap'].forEach(function (wrapId) {
    var wrap = document.getElementById(wrapId);
    if (wrap && !wrap.contains(e.target)) {
      var dd = wrap.querySelector('.search-dropdown');
      if (dd) dd.classList.remove('open');
    }
  });
});
function populateBulkPartTypes(types) {
  bulkPartTypesList = types || [];
  makeSearchable('bulk_part_type_search', 'bulk_part_type_dropdown', 'bulk_part_type', function () {
    return bulkPartTypesList;
  }, 'name', 'part_type_id');
}
function populateBulkLocations(locations) {
  bulkLocationsList = (locations || []).map(function (l) {
    return {
      location_id: l.location_id,
      label: l.location_code + ' — ' + l.location_name
    };
  });
  makeSearchable('bulk_location_search', 'bulk_location_dropdown', 'bulk_location', function () {
    return bulkLocationsList;
  }, 'label', 'location_id');
}
function renderBulkOrders(orders) {
  var tbody = document.getElementById('bulk_orders_body');
  if (!tbody) return;
  if (!orders || !orders.length) {
    tbody.innerHTML = '<tr><td colspan="8" class="empty">No bulk orders</td></tr>';
    return;
  }
  tbody.innerHTML = orders.map(function (o) {
    var statusClass = o.status === 'Received' ? 'badge-received' : 'badge-pending';
    var action = o.status === 'Pending' ? '<button class="btn btn-order" style="height:28px;font-size:11px;padding:0 10px" onclick="window.receiveBulkOrder(' + o.order_id + ')">Mark Received</button>' : '—';
    return '<tr>' + '<td>' + (o.part_description || '—') + '</td>' + '<td>' + (o.supplier || '—') + '</td>' + '<td style="font-family:monospace;font-size:11px">' + (o.order_ref || '—') + '</td>' + '<td>' + (o.quantity || 1) + '</td>' + '<td>' + (o.unit_cost ? '£' + Number(o.unit_cost).toFixed(2) : '—') + '</td>' + '<td>' + fmt(o.expected_delivery) + '</td>' + '<td><span class="badge ' + statusClass + '">' + (o.status || 'Pending') + '</span></td>' + '<td>' + action + '</td>' + '</tr>';
  }).join('');
}
window.raiseBulkOrder = function () {
  var partTypeId = document.getElementById('bulk_part_type').value;
  var desc = toTitleCase(document.getElementById('bulk_desc').value.trim());
  var locationId = document.getElementById('bulk_location').value;
  if (!partTypeId) {
    alert('Please select a part type');
    return;
  }
  if (!desc) {
    alert('Please enter a description');
    return;
  }
  if (!locationId) {
    alert('Please select a stock location');
    return;
  }
  appsmith.updateModel({
    bulkOrder: {
      part_type_id: partTypeId,
      part_description: desc,
      supplier: toTitleCase(document.getElementById('bulk_supplier').value.trim()),
      order_ref: document.getElementById('bulk_ref').value.trim(),
      unit_cost: parseFloat(document.getElementById('bulk_cost').value) || 0,
      quantity: parseInt(document.getElementById('bulk_qty').value) || 1,
      expected_delivery: document.getElementById('bulk_delivery').value || null,
      notes: toTitleCase(document.getElementById('bulk_notes').value.trim()),
      location_id: locationId
    }
  });
  appsmith.triggerEvent('onRaiseBulkOrder');
  document.getElementById('bulk_part_type').value = '';
  document.getElementById('bulk_part_type_search').value = '';
  document.getElementById('bulk_desc').value = '';
  document.getElementById('bulk_supplier').value = '';
  document.getElementById('bulk_ref').value = '';
  document.getElementById('bulk_cost').value = '';
  document.getElementById('bulk_qty').value = '1';
  document.getElementById('bulk_delivery').value = '';
  document.getElementById('bulk_notes').value = '';
  document.getElementById('bulk_location').value = '';
  document.getElementById('bulk_location_search').value = '';
  var msg = document.getElementById('bulk_success');
  if (msg) {
    msg.style.display = 'block';
    setTimeout(function () {
      msg.style.display = 'none';
    }, 3000);
  }
};
window.receiveBulkOrder = function (orderId) {
  appsmith.updateModel({
    receivingBulkOrderId: orderId
  });
  appsmith.triggerEvent('onReceiveBulkOrder');
};
function render(model) {
  populateBulkPartTypes(model.partTypes || []);
  populateBulkLocations(model.locations || []);
  renderBulkOrders(model.orders || []);
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

